@namespace sv_b433050825eb4d0c9447849e7c0bfee4.Components.JobApplication

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var isCurrent = step == CurrentStep;
        var isCompleted = CompletedSteps.Contains(step);
        var isFuture = !isCurrent && !isCompleted;

        <div class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
             role="button"
             @onclick="() => HandleStepClick(step)">
            <div class="step-circle mx-auto mb-1 rounded-circle d-flex align-items-center justify-content-center
                        @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-secondary text-white")"
                 style="width:36px;height:36px;font-size:0.85rem;">
                @if (isCompleted)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <small class="@(isFuture ? "text-muted" : "")">@StepNames[step]</small>
        </div>

        @if (step < StepNames.Count - 1)
        {
            <div class="step-connector align-self-center flex-fill" style="height:2px;max-width:40px;margin-top:-12px;"
                 class="@(CompletedSteps.Contains(step) ? "bg-success" : "bg-secondary")">
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@namespace sv_b433050825eb4d0c9447849e7c0bfee4.Components.JobApplication

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @ReferenceNumber</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="HandleRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name</label>
                <input type="text" class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input type="text" class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

