+@namespace sv_b433050825eb4d0c9447849e7c0bfee4.Components.JobApplication
+
+<div class="step-indicator d-flex justify-content-between mb-4">
+    @for (int i = 0; i < StepNames.Count; i++)
+    {
+        var step = i;
+        var isCurrent = step == CurrentStep;
+        var isCompleted = CompletedSteps.Contains(step);
+        var isFuture = !isCurrent && !isCompleted;
+
+        <div class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
+             role="button"
