{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   ReferenceNumber="index + 1"
                   ShowRemove="References.Count > 2"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
